const items = [];

for (const input of $input.all()) {
  const body = input.json.data || input.json.body || '';

  if (typeof body === 'string' && body.includes('<item>')) {
    const regex = /<item>[\s\S]*?<title>(?:<!\[CDATA\[)?([^<\]]+)(?:\]\]>)?<\/title>[\s\S]*?<link>([^<]+)<\/link>[\s\S]*?<\/item>/g;
    let match;
    while ((match = regex.exec(body)) !== null) {
      items.push({ json: { title: match[1].trim(), url: match[2].trim(), source: 'Google News' } });
    }
  }

  if (input.json && input.json.data && input.json.data.children) {
    for (const child of input.json.data.children) {
      const post = child.data;
      if (post && post.title) {
        items.push({ json: { title: post.title, url: 'https://reddit.com' + post.permalink, source: 'Reddit r/SaaS' } });
      }
    }
  }
}

const keywords = ['saas', 'software', 'automation', 'ai', 'startup', 'niche', 'vertical', 'workflow', 'crm', 'api', 'platform', 'subscription', 'tool', 'app'];
const seen = new Set();
const filtered = [];

for (const item of items) {
  const title = item.json.title.toLowerCase();
  if (!title || seen.has(title)) continue;
  if (!keywords.some(kw => title.includes(kw))) continue;
  seen.add(title);
  filtered.push(item);
}

return filtered.slice(0, 5);

// Build Anthropic request body as a safe JSON string
const title = $json.title || '';
const prompt = 'Score this SaaS idea on 8 criteria (0-10 each). Idea: ' + title + '\n\nCriteria: market size (market), automation potential (automation), pain intensity (pain), low competition = high score (competition), willingness to pay (willingnessToPay), profit margin (margin), build complexity - low = easy (build), market timing (timing).\n\nReply ONLY with this JSON structure, no markdown, no extra text:\n{"market":7,"automation":8,"pain":6,"competition":5,"willingnessToPay":7,"margin":8,"build":7,"timing":6,"summary":"One sentence about this idea in Russian"}';

const body = {
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 400,
  messages: [{ role: 'user', content: prompt }]
};

return [{
  json: {
    title: $json.title,
    url: $json.url,
    source: $json.source,
    requestBody: JSON.stringify(body)
  }
}];

const results = [];

for (const item of $input.all()) {
  try {
    const response = item.json;
    let scoreData = null;

    if (response.content && response.content[0] && response.content[0].text) {
      const text = response.content[0].text.trim();
      const jsonMatch = text.match(/\{[\s\S]*?\}/);
      if (jsonMatch) scoreData = JSON.parse(jsonMatch[0]);
    }

    if (!scoreData) continue;

    const weights = { market:0.15, automation:0.20, pain:0.15, competition:0.10, willingnessToPay:0.10, margin:0.10, build:0.10, timing:0.10 };
    let composite = 0;
    for (const [k, w] of Object.entries(weights)) composite += (scoreData[k] || 0) * w;
    composite = Math.round(composite * 10) / 10;

    let verdict = 'KILL';
    if (composite >= 8.0) verdict = 'BUILD';
    else if (composite >= 6.5) verdict = 'BET';
    else if (composite >= 4.5) verdict = 'FLIP';

    const sourceIdea = $('Подготовить запрос').item.json;

    results.push({
      json: {
        id: Date.now() + Math.floor(Math.random() * 1000),
        title: sourceIdea.title,
        description: scoreData.summary || '',
        source: sourceIdea.source,
        sourceUrl: sourceIdea.url || '',
        scoreComposite: composite,
        verdict,
        verdictReason: scoreData.summary || '',
        status: 'new',
        discoveredAt: new Date().toISOString(),
        scores: {
          market: scoreData.market || 0,
          automation: scoreData.automation || 0,
          pain: scoreData.pain || 0,
          competition: scoreData.competition || 0,
          willingnessToPay: scoreData.willingnessToPay || 0,
          margin: scoreData.margin || 0,
          build: scoreData.build || 0,
          timing: scoreData.timing || 0
        }
      }
    });
  } catch(e) {}
}

return results;

const fs = require('fs');
const filePath = 'C:/autonomy-data/ideas.json';

if (!fs.existsSync('C:/autonomy-data')) fs.mkdirSync('C:/autonomy-data', { recursive: true });

let existing = [];
try { existing = JSON.parse(fs.readFileSync(filePath, 'utf8')); } catch(e) {}

const existingTitles = new Set(existing.map(i => i.title.toLowerCase()));
const newIdeas = [];

for (const item of $input.all()) {
  const idea = item.json;
  if (!existingTitles.has(idea.title.toLowerCase())) {
    existing.push(idea);
    newIdeas.push(idea);
  }
}

const tenDaysAgo = new Date();
tenDaysAgo.setDate(tenDaysAgo.getDate() - 10);
existing = existing.filter(idea => {
  if (idea.verdict === 'KILL' || idea.verdict === 'FLIP') return new Date(idea.discoveredAt) > tenDaysAgo;
  return true;
});

fs.writeFileSync(filePath, JSON.stringify(existing, null, 2), 'utf8');

return [{ json: { status: 'success', newIdeas: newIdeas.length, totalIdeas: existing.length, timestamp: new Date().toISOString() } }];
